lappend.example:
set layers {}
lappend layers "Silicon" "Oxide" "Metal"
puts $layers  ;# prints: Silicon Oxide Metal

variable.example:
namespace eval Device {
  variable thickness 0.1
  variable material "Silicon"
}
puts $Device::thickness  ;# prints: 0.1

rename.example:
proc my_puts {args} {
  puts "LOG: $args"
}
rename puts original_puts
rename my_puts puts

global.example:
set device_name "NMOS"
proc get_device {} {
  global device_name
  return $device_name
}
puts [get_device]  ;# prints: NMOS

uplevel.example:
proc do_in_global {script} {
  uplevel #0 $script
}
set result 0
do_in_global {set result 42}
puts $result  ;# prints: 42

catch.example:
if {[catch {open "data.txt" r} fid]} {
  puts "Error opening file: $fid"
} else {
  puts [read $fid]
  close $fid
}

error.example:
proc check_voltage {v} {
  if {$v < 0} {
    error "Voltage must be non-negative, got $v"
  }
  return $v
}

try.example:
try {
  set fid [open "result.dat" r]
  set data [read $fid]
} catch {POSIX EACCES} {
  puts "Permission denied"
} finally {
  if {[info exists fid]} { close $fid }
}

throw.example:
proc simulate {bias} {
  if {$bias > 100} {
    throw SIMULATION "Bias $bias exceeds safe limit (100V)"
  }
}

regexp.example:
set line "Id = 1.23e-3 A/V"
if {[regexp {Id\s*=\s*([\d.e+-]+)} $line -> id_val]} {
  puts "Current: $id_val"  ;# prints: Current: 1.23e-3
}

lindex.example:
set dims {1e-4 5e-6 1e-4}
puts [lindex $dims 0]   ;# prints: 1e-4 (length)
puts [lindex $dims end] ;# prints: 1e-4 (depth)

lrange.example:
set vals {10 20 30 40 50}
puts [lrange $vals 1 3]   ;# prints: 20 30 40
puts [lrange $vals 2 end] ;# prints: 30 40 50

lreplace.example:
set bias {0.0 0.5 1.0 1.5}
set new_bias [lreplace $bias 2 2 1.2]
puts $new_bias  ;# prints: 0.0 0.5 1.2 1.5

lsearch.example:
set mats {Silicon Oxide Aluminum Copper}
puts [lsearch -exact $mats Oxide]     ;# prints: 1
puts [lsearch -inline $mats Al*]       ;# prints: Aluminum

lsort.example:
set vals {3.14 1.0 2.71 0.5}
puts [lsort -real $vals]          ;# prints: 0.5 1.0 2.71 3.14
puts [lsort -real -decreasing $vals] ;# prints: 3.14 2.71 1.0 0.5

join.example:
set parts {Silicon Oxide Metal}
puts [join $parts " -> "]  ;# prints: Silicon -> Oxide -> Metal
puts [join $parts "/"]     ;# prints: Silicon/Oxide/Metal

gets.example:
set fid [open "data.csv" r]
while {[gets $fid line] >= 0} {
  puts $line
}
close $fid

file.example:
if {[file exists "result.dat"]} {
  set size [file size "result.dat"]
  puts "File exists, size: $size bytes"
}
file mkdir "output"
set ext [file extension "run_des.cmd"]  ;# returns .cmd

glob.example:
set cmd_files [glob -nocomplain *_des.cmd]
foreach f $cmd_files {
  puts "Found: $f"
}
set all_dirs [glob -types d *]

info.example:
if {[info exists env(HOME)]} {
  puts "Home: $env(HOME)"
}
puts [info procs]     ;# list all procedures
puts [info patchlevel] ;# e.g., 8.6.12

array.example:
array set params {temp 300 bias 1.2 model "Boltzmann"}
puts [array size params]          ;# prints: 3
puts [array names params]          ;# prints: temp bias model
foreach key [array names params] {
  puts "$key = $params($key)"
}

after.example:
after 1000 {puts "One second later"}
set id [after 500 {update_status}]
after cancel $id

concat.example:
set a {1 2 3}
set b {4 5}
set result [concat $a $b]  ;# returns 1 2 3 4 5
set nested [concat {{a b} {c d}}] ;# returns a b c d

for.example:
for {set i 0} {$i < 5} {incr i} {
  puts "Iteration $i"
}
# 输出: Iteration 0 到 Iteration 4

foreach.example:
set voltages {0.0 0.5 1.0 2.0}
foreach v $voltages {
  puts "Bias: $v V"
}
foreach v $voltages i {1 2 3 4} {
  puts "Step $i: $v V"
}

while.example:
set x 1
while {$x < 10} {
  puts "x = $x"
  set x [expr {$x * 2}]
}
# 输出: x = 1, x = 2, x = 4, x = 8

if.example:
set temp 350
if {$temp > 400} {
  puts "High temperature warning"
} elseif {$temp > 300} {
  puts "Normal operating range"
} else {
  puts "Below ambient"
}

switch.example:
set solver "Newton"
switch $solver {
  "Newton"   { puts "Using Newton method" }
  "Explicit" { puts "Using explicit scheme" }
  default    { puts "Unknown solver: $solver" }
}

return.example:
proc compute {x} {
  if {$x < 0} { return -code error "Negative input" }
  return [expr {$x * 2}]
}

break.example:
foreach val {1 2 3 4 5} {
  if {$val == 3} { break }
  puts $val
}
;# 输出: 1 2

continue.example:
for {set i 0} {$i < 5} {incr i} {
  if {$i == 2} { continue }
  puts $i
}
;# 输出: 0 1 3 4

update.example:
set step 0
while {$step < 1000} {
  incr step
  if {$step % 100 == 0} { update }
}

exit.example:
if {$converged} {
  exit 0
} else {
  puts "Simulation failed"
  exit 1
}

lassign.example:
set pair {1.2 0.8}
lassign $pair vg vd
puts "Vg=$vg, Vd=$vd"  ;# 输出: Vg=1.2, Vd=0.8

lset.example:
set matrix {{0 0} {0 0}}
lset matrix 0 1 5
puts $matrix  ;# 输出: {0 5} {0 0}
